:root {
  --bg-color: #f4f7f6;
  --card-bg: #ffffff;
  --primary: #2c3e50;
  --accent: #3498db;
  --text: #333;
  --text-dim: #7f8c8d;
  --border: #ddd;
  --danger: #e74c3c;
  --success: #27ae60;
}

.governance-container {
  background-color: var(--bg-color);
  color: var(--text);
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  padding: 20px;
  min-height: 100vh;
}

/* Added wrapper for max-width constraint */
.governance-wrapper {
  max-width: 1200px;
  margin: 0 auto;
}

.gov-header {
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: 30px;
  border-bottom: 1px solid var(--border);
  padding-bottom: 20px;
}

.brand {
  text-align: center;
}

.brand h1 {
  margin: 0;
  color: var(--primary);
}

.brand .subtitle {
  color: #000000;
  font-size: 1.1rem;
  margin: 8px 0 0 0;
}

.risk-badge {
  position: absolute;
  right: 0;
  padding: 8px 20px;
  border-radius: 9999px;
  font-weight: bold;
  font-size: 1.2 rem;
}

.risk-badge.low {
  background: var(--success);
  color: #ffffff;
}

.risk-badge.high {
  background: var(--danger);
  color: #ffffff;
}

.gov-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 20px;
  margin-bottom: 40px;
}

.gov-card {
  background: var(--card-bg);
  padding: 20px;
  border-radius: 8px;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  text-align: center;
  border-top: 4px solid var(--accent);
}

.gov-card label {
  display: block;
  color: var(--text-dim);
  font-size: 1.2rem;
  margin: 0;
  text-transform: uppercase;
  font-weight: bold;
}

.gov-card .value {
  font-size: 2rem;
  font-weight: bold;
  color: var(--text);
  margin: 10px 0 0;
}

.gov-card small {
  color: var(--text-dim);
  font-size: 0.75rem;
  display: block;
  margin-top: 4px;
}

.audit-section {
  background: var(--card-bg);
  border-radius: 8px;
  overflow: hidden;
  box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  padding: 20px;
}

.audit-section h3 {
  margin-top: 0;
  margin-bottom: 15px;
  font-size: 1.1rem;
  color: var(--primary);
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 10px;
}

th {
  background-color: #f8f9fa;
  color: var(--primary);
  text-align: left;
  padding: 12px;
  font-size: 1.2rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 1px solid var(--border);
}

td {
  padding: 12px;
  border-bottom: 1px solid var(--border);
  font-size: 1.2rem;
  color: var(--text);
}

tr:hover {
  background-color: #f1f1f1;
}

tr:nth-child(even) {
  background-color: #fafafa;
}

.risk-tag {
  padding: 4px 8px;
  border-radius: 4px;
  font-size: 1.2rem;
  font-weight: bold;
}

.risk-high {
  background: #f8d7da;
  color: #721c24;
  border: 1px solid #f5c6cb;
}

.risk-none {
  background: #d4edda;
  color: #155724;
  border: 1px solid #c3e6cb;
}

