appsmith.onReady(renderDashboard);
appsmith.onModelChange(renderDashboard);
const riskPriority = {
  "CRITICAL": 3,
  "LARGE PAYLOAD": 2,
  "LOW": 1
};
function renderDashboard() {
  const data = appsmith.model.networkEvents;
  if (!data || !Array.isArray(data)) return;
  const tableBody = document.querySelector('#audit-body');
  if (!tableBody) return;
  tableBody.innerHTML = "";
  let sanitizationActive = false;
  let shadowAICount = 0;
  let totalExfiltratedSize = 0;
  const sanctionedAI = ["vertex-ai.googleapis.com", "your-internal-proxy.io", "revolut.com"];
  const unsanctionedAI = ["api.openai.com", "claude.ai", "mistral.ai", "perplexity.ai", "googletagmanager.com"];

  // STEP A: Process Security Headers
  data.forEach(event => {
    if (event.method === "Network.responseReceived") {
      const headers = event.params.response.headers || {};
      // x-xss-protection indicates active sanitization 
      if (headers['x-xss-protection'] || headers['X-XSS-Protection']) {
        sanitizationActive = true;
      }
    }
  });

  // STEP B: Map and Calculate Risk
  const processedRequests = data.filter(event => event.method === "Network.requestWillBeSent").map(req => {
    const urlStr = req.params.request.url;
    let domain = "unknown";
    try {
      domain = new URL(urlStr).hostname;
    } catch (e) {
      domain = urlStr;
    }
    const headers = req.params.request.headers || {};
    const contentLength = headers['Content-Length'] || headers['content-length'] || 0;
    const payloadSize = parseInt(contentLength) || 0;
    const isShadow = unsanctionedAI.some(ai => domain.includes(ai));
    const isSanctioned = sanctionedAI.some(ai => domain.includes(ai));
    let riskLevel = "LOW";
    if (isShadow) {
      riskLevel = "CRITICAL";
    } else if (payloadSize > 50000) {
      riskLevel = "LARGE PAYLOAD";
    }
    return {
      ...req,
      domain,
      isShadow,
      isSanctioned,
      payloadSize,
      riskLevel
    };
  });
  processedRequests.sort((a, b) => riskPriority[b.riskLevel] - riskPriority[a.riskLevel]);

  // STEP C: Render Table
  processedRequests.forEach(req => {
    totalExfiltratedSize += req.payloadSize;
    if (req.isShadow) shadowAICount++;
    const riskBg = req.riskLevel === "LOW" ? "#e8f8f5" : req.riskLevel === "CRITICAL" ? "#fce4e4" : "#fcf3cf";
    const riskColor = req.riskLevel === "LOW" ? "#1e8449" : req.riskLevel === "CRITICAL" ? "#c0392b" : "#d35400";
    const row = document.createElement('tr');
    row.innerHTML = `
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><code>${req.domain}</code></td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;">${req.isShadow || req.isSanctioned ? 'AI INFERENCE' : req.params.type}</td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><span style="padding: 4px 8px; border-radius: 12px; font-size: 0.75rem; font-weight: bold; background-color: #f8f9fa; color: #2c3e50; border: 1px solid #bdc3c7;">mTLS Observed</span></td>
            <td style="padding: 12px; border-bottom: 1px solid #eee;"><span style="padding: 4px 8px; border-radius: 12px; font-size: 0.75rem; font-weight: bold; background-color: ${riskBg}; color: ${riskColor};">${req.riskLevel}</span></td>
            <td style="padding: 12px; border-bottom: 1px solid #eee; font-weight:bold; color: ${req.isShadow ? '#c0392b' : '#3498db'};">${req.isShadow ? 'SIGNAL' : 'AUDITED'}</td>
        `;
    tableBody.appendChild(row);
  });
  document.getElementById('shadow-ai-count').textContent = shadowAICount;
  document.getElementById('token-count').textContent = (totalExfiltratedSize / 1024).toFixed(1) + " KB";

  // Applying user preference: "Shield On" (now "Observed") text is green and smaller
  const sanitizationEl = document.getElementById('sanitization-status');
  if (sanitizationActive) {
    sanitizationEl.innerHTML = `<span style="color: #27ae60; font-size: 0.8rem;">Observed</span>`;
  } else {
    sanitizationEl.innerHTML = `<span style="color: #e74c3c; font-size: 0.8rem;">Not Detected</span>`;
  }
  const riskBadge = document.getElementById('risk-score');
  if (shadowAICount > 0) {
    riskBadge.textContent = "Threat Signal: HIGH";
    riskBadge.style.background = "#e74c3c";
  } else {
    riskBadge.textContent = "Threat Signal: Nominal";
    riskBadge.style.background = "#2ecc71";
  }
}

